183	// resolveExecuteRoute reduces the request to a concrete RouteDecision.
184	// The request is dispatched through the routing engine
185	// (internal/routing.Resolve) when under-specified, or accepted verbatim
186	// when Harness is set explicitly.
187	func (s *service) resolveExecuteRoute(req ServiceExecuteRequest) (*RouteDecision, error) {
188		// If Harness is omitted but the engine has enough hints (Profile/ModelRef/
189		// Model/Provider) to disambiguate, route through ResolveRoute.
190		if req.Harness == "" {
191			if req.Profile == "" && req.ModelRef == "" && req.Model == "" && req.Provider == "" {
192				return nil, fmt.Errorf("routing under-specified: pass at least one of Harness/Profile/ModelRef/Model/Provider, or auto-selection inputs")
193			}
194			return s.resolveExecuteRouteWithEngine(req)
195		}
196		canonical := harnesses.ResolveHarnessAlias(req.Harness)
197		if !s.registry.Has(canonical) {
198			return nil, fmt.Errorf("unknown harness %q", req.Harness)
199		}
200		cfg, _ := s.registry.Get(canonical)
201		if err := validateExplicitHarnessProfile(canonical, cfg, req.Profile); err != nil {
202			return nil, err
203		}
204		if err := validateExplicitProvider(s.opts.ServiceConfig, cfg, req.Provider); err != nil {
205			return nil, err
206		}
207		if err := validateExplicitHarnessModel(canonical, cfg, req.Model, req.Provider); err != nil {
208			return nil, err
209		}
210		if err := validateExplicitHarnessReasoning(canonical, cfg, req.Reasoning); err != nil {
211			return nil, err
212		}
213		return &RouteDecision{
214			Harness:  canonical,
215			Provider: req.Provider,
216			Model:    resolveSubprocessModelAlias(canonical, req.Model),
217			Reason:   "explicit",
218		}, nil
219	}
