221	func validateExplicitHarnessProfile(name string, cfg harnesses.HarnessConfig, profile string) error {
222		constraint, ok := explicitProfileConstraint(profile)
223		if !ok {
224			return nil
225		}
226		switch constraint {
227		case routing.ProviderPreferenceLocalOnly:
228			if !cfg.IsLocal {
229				return &ErrProfilePinConflict{
230					Profile:           profile,
231					ConflictingPin:    "Harness=" + name,
232					ProfileConstraint: constraint,
233				}
234			}
235		case routing.ProviderPreferenceSubscriptionOnly:
236			if !cfg.IsSubscription {
237				return &ErrProfilePinConflict{
238					Profile:           profile,
239					ConflictingPin:    "Harness=" + name,
240					ProfileConstraint: constraint,
241				}
242			}
243		}
244		return nil
245	}
