247	func explicitProfileConstraint(profile string) (string, bool) {
248		switch profile {
249		case "local", "offline", "air-gapped":
250			return routing.ProviderPreferenceLocalOnly, true
251		case "smart", "code-smart", "code-high":
252			return routing.ProviderPreferenceSubscriptionOnly, true
253		default:
254			return "", false
255		}
256	}
